const raw = $json.body ?? $json;
let data = raw;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch { data = {}; }
}
if (typeof data !== 'object' || data === null || Array.isArray(data)) { data = {}; }

const pick = (obj, keys, fallback = '') => {
  for (const key of keys) {
    const val = obj[key];
    if (val !== undefined && val !== null && String(val).trim() !== '') {
      return typeof val === 'string' ? val.trim() : String(val);
    }
  }
  return fallback;
};

const normalizePhone = (value) => {
  const digitsOnly = String(value ?? '').replace(/\D/g, '');
  if (!digitsOnly) return '';

  let br = digitsOnly;
  if (br.startsWith('55') && br.length > 11) br = br.slice(2);
  br = br.slice(0, 11);

  return br ? `'${br}` : '';
};

const dateBR = new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const nome  = pick(data, ['nome', 'Nome completo'], '');
const email = pick(data, ['email', 'Qual seu e-mail?'], '');

const wppRaw  = pick(data, ['whatsapp', 'Qual o seu WhatsApp?', 'Qual o seu WhatsApp', 'WhatsApp'], '');
const wpp2Raw = pick(data, ['whatsapp_confirmacao', 'Confirme seu WhatsApp', 'Confirmar WhatsApp'], '');
const wpp  = normalizePhone(wppRaw);
const wpp2 = normalizePhone(wpp2Raw);

const medalha = pick(data, ['nivel_ml', 'Qual é a sua medalha no Mercado Livre?'], '');
const regime  = pick(data, ['regime_tributario', 'Qual é o seu regime tributário atual?'], '');

const nivelLabels = {
  sem_medalha: 'Sem medalha',
  ouro:        'Ouro',
  ouro_plus:   'Ouro Plus',
  platinum:    'Platinum'
};
const regimeLabels = {
  mei:               'MEI',
  simples_nacional:  'Simples Nacional',
  lucro_presumido:   'Lucro Presumido',
  lucro_real:        'Lucro Real'
};
const medalhaLegivel = nivelLabels[medalha] || medalha;
const regimeLegivel  = regimeLabels[regime]  || regime;

const channel  = pick(data, ['channel', 'canal'], '');
const source   = pick(data, ['utm_source', 'source'], '');
const medium   = pick(data, ['utm_medium', 'medium'], '');
const campaign = pick(data, ['utm_campaign', 'campaign'], '');
const content  = pick(data, ['utm_content', 'content'], '');
const referrer = pick(data, ['referrer'], '');
const pageUrl  = pick(data, ['page_url'], '');
const timestamp = pick(data, ['timestamp'], new Date().toISOString());
const mql      = pick(data, ['mql'], '');

return [{
  json: {
    'Entrada leads':         dateBR,
    'Funil':                 'Tributario',
    'Nome completo':         nome,
    'Qual seu e-mail?':      email,
    'Qual o seu WhatsApp?':  wpp,
    'Confirme seu WhatsApp': wpp2,
    'Pergunta adicional':    `Medalha ML: ${medalhaLegivel} | Regime: ${regimeLegivel}`,
    channel,
    'Source':   source,
    'Medium':   medium,
    'Campaign': campaign,
    'Content':  content,
    'Referrer': referrer,
    'Page URL': pageUrl,
    timestamp,
    'MQL': mql
  }
}];
